from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_login import LoginManager, login_required, current_user

app = Flask(__name__)
db = SQLAlchemy(app)
login_manager = LoginManager(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(80), unique=True, nullable=False)
    account_type = db.Column(db.String(50), nullable=False)
    credits = db.Column(db.Integer, default=0)
    referral_code = db.Column(db.String(50))
    verified_status = db.Column(db.Boolean, default=False)

@app.route('/update_profile', methods=['PATCH'])
@login_required
def update_profile():
    data = request.json
    for field in data:
        if hasattr(current_user, field):
            setattr(current_user, field, data[field])
    db.session.commit()
    return jsonify({"message": "Profile updated successfully", "user": { 
        "email": current_user.email,
        "username": current_user.username,
        "account_type": current_user.account_type,
        "credits": current_user.credits,
        "referral_code": current_user.referral_code,
        "verified_status": current_user.verified_status,
    }}), 200

